//#region src/utils/mempool.ts
/**
* @deprecated Use `SparkWallet.getUtxosForDepositAddress()` instead.
* Retrieves the most recent transaction that pays to the given deposit address
* by querying the electrs HTTP API. Retained only for backwards compatibility
* and will be removed in a future release.
*/
async function getLatestDepositTxId(address) {
	const { fetch, Headers } = getFetch();
	const network = getNetworkFromAddress(address);
	const baseUrl = network === BitcoinNetwork.REGTEST ? getElectrsUrl("REGTEST") : getElectrsUrl("MAINNET");
	const headers = new Headers();
	if (network === BitcoinNetwork.REGTEST) {
		const auth = btoa(`${ELECTRS_CREDENTIALS.username}:${ELECTRS_CREDENTIALS.password}`);
		headers.set("Authorization", `Basic ${auth}`);
	}
	const addressTxs = await (await fetch(`${baseUrl}/address/${address}/txs`, { headers })).json();
	if (addressTxs && addressTxs.length > 0) {
		const latestTx = addressTxs[0];
		if (latestTx.vout.findIndex((output) => output.scriptpubkey_address === address) === -1) return null;
		return latestTx.txid;
	}
	return null;
}
async function isTxBroadcast(txid, baseUrl, network) {
	const { fetch, Headers } = getFetch();
	const headers = new Headers();
	if (network === Network.REGTEST) {
		const auth = btoa(`${ELECTRS_CREDENTIALS.username}:${ELECTRS_CREDENTIALS.password}`);
		headers.set("Authorization", `Basic ${auth}`);
	}
	if ((await (await fetch(`${baseUrl}/tx/${txid}`, { headers })).json()).error) return false;
	return true;
}

