//#region src/utils/proof.ts
function proofOfPossessionMessageHashForDepositAddress(userPubkey, operatorPubkey, depositAddress) {
	const depositAddressBytes = new TextEncoder().encode(depositAddress);
	return newHasher([
		"spark",
		"deposit",
		"proof_of_possession"
	]).addBytes(userPubkey).addBytes(operatorPubkey).addBytes(depositAddressBytes).hash();
}

//#endregion
//#region src/utils/response-validation.ts
function collectResponses(responses) {
	const successfulResponses = responses.filter((result) => result.status === "fulfilled").map((result) => result.value);
	const failedResponses = responses.filter((result) => result.status === "rejected");
	if (failedResponses.length > 0) {
		const errors = failedResponses.map((result) => result.reason).join("\n");
		throw new SparkRequestError(`${failedResponses.length} out of ${responses.length} requests failed, please try again`, {
			errorCount: failedResponses.length,
			errors,
			error: failedResponses.map((result) => result.reason)
		});
	}
	return successfulResponses;
}

