	async verifyPendingTransfer(transfer) {
		const leafPubKeyMap = /* @__PURE__ */ new Map();
		await Promise.all(transfer.leaves.map(async (leaf) => {
			if (!leaf.leaf) throw new Error("Leaf is undefined");
			const encoder = new TextEncoder();
			const leafIdBytes = encoder.encode(leaf.leaf.id);
			const transferIdBytes = encoder.encode(transfer.id);
			const payloadHash = sha256(new Uint8Array([
				...leafIdBytes,
				...transferIdBytes,
				...leaf.secretCipher
			]));
			if (!secp256k1.verify(leaf.signature, payloadHash, transfer.senderIdentityPublicKey)) throw new Error("Signature verification failed");
			const leafSecret = await this.config.signer.decryptEcies(leaf.secretCipher);
			leafPubKeyMap.set(leaf.leaf.id, leafSecret);
		}));
		return leafPubKeyMap;
	}
