//#region src/utils/htlc-transactions.ts
const PUB_KEY_BYTES = "0250929b74c1a04954b78b4b6035e97a5e078a5a0f28ec96d547bfee9ace803ac0";
function numsPoint() {
	const withdrawalPubKey = secp256k1.Point.fromHex(PUB_KEY_BYTES).toBytes(true).slice(1);
	return Buffer.from(withdrawalPubKey);
}
const lightningHTLCSequence = 2160;
function createRefundTxsForLightning({ nodeTx, directNodeTx, vout, sequence, directSequence, directInput, network, hash, hashLockDestinationPubkey, sequenceLockDestinationPubkey }) {
	const cpfpRefundTx = createLightningHTLCTransaction({
		nodeTx,
		sequence,
		vout,
		hash,
		hashLockDestinationPubkey,
		sequenceLockDestinationPubkey,
		applyFee: false,
		network
	});
	const directFromCpfpRefundTx = createLightningHTLCTransaction({
		nodeTx,
		sequence: directSequence,
		vout,
		hash,
		hashLockDestinationPubkey,
		sequenceLockDestinationPubkey,
		applyFee: true,
		network
	});
	let directRefundTx;
	if (directSequence && directNodeTx) directRefundTx = createLightningHTLCTransaction({
		nodeTx: directNodeTx,
		sequence: directSequence,
		vout,
		hash,
		hashLockDestinationPubkey,
		sequenceLockDestinationPubkey,
		applyFee: true,
		network
	});
	else if (directInput && !directSequence) throw new SparkValidationError("directSequence must be provided if directInput is", {
		field: "directSequence",
		value: directSequence
	});
	return {
		cpfpRefundTx,
		directRefundTx,
		directFromCpfpRefundTx
	};
}
function createLightningHTLCTransaction({ nodeTx, vout, sequence, hash, hashLockDestinationPubkey, sequenceLockDestinationPubkey, applyFee, network }) {
	let outAmount = nodeTx.getOutput(vout)?.amount ?? 0n;
	if (applyFee) outAmount = maybeApplyFee(outAmount);
	const input = {
		txid: hexToBytes(getTxId(nodeTx)),
		index: 0
	};
	const htlcTransaction = new Transaction({
		version: 3,
		allowUnknownOutputs: true
	});
	htlcTransaction.addInput({
		...input,
		sequence
	});
	const taprootAddress = createHTLCTaprootAddress({
		hash,
		hashLockDestinationPubkey,
		sequence: lightningHTLCSequence,
		sequenceLockDestinationPubkey,
		network
	});
	htlcTransaction.addOutput({
		script: taprootAddress,
		amount: outAmount
	});
	if (!applyFee) htlcTransaction.addOutput(getEphemeralAnchorOutput());
	return htlcTransaction;
}
function createHTLCTaprootAddress({ hash, hashLockDestinationPubkey, sequence, sequenceLockDestinationPubkey, network }) {
	const numsKey = numsPoint();
	const hashLockScript = createHashLockScript(hash, hashLockDestinationPubkey);
	const sequenceLockScript = createSequenceLockScript(sequence, sequenceLockDestinationPubkey);
	return p2tr(numsKey, taprootListToTree([{
		leafVersion: 192,
		script: hashLockScript
	}, {
		leafVersion: 192,
		script: sequenceLockScript
	}]), network, true).script;
}
function createHashLockScript(hash, pubkey) {
	return Script.encode([
		"SHA256",
		hash,
		"EQUALVERIFY",
		pubkey.slice(1, 33),
		"CHECKSIG"
	]);
}
function createSequenceLockScript(sequence, sequenceLockDestinationPubkey) {
	const seqOperand = sequence >= 0 && sequence <= 16 ? sequence : ScriptNum().encode(BigInt(sequence));
	return Script.encode([
		seqOperand,
		"CHECKSEQUENCEVERIFY",
		"DROP",
		sequenceLockDestinationPubkey.slice(1, 33),
		"CHECKSIG"
	]);
}
function createSenderSpendTx({ htlcTx, network, hash, hashLockDestinationPubkey, sequenceLockDestinationPubkey, fee }) {
	const numsKey = numsPoint();
	const senderSpendTx = new Transaction({
		version: 3,
		allowUnknownOutputs: true,
		allowUnknownInputs: true
	});
	senderSpendTx.addInput({
		txid: hexToBytes(getTxId(htlcTx)),
		index: 0,
		sequence: lightningHTLCSequence
	});
	const senderP2TR = p2tr(sequenceLockDestinationPubkey.slice(1, 33), void 0, network, true).script;
	const amount = htlcTx.getOutput(0)?.amount - BigInt(fee);
	if (amount <= 0n) throw new SparkValidationError("Fee is greater than the amount", {
		field: "fee",
		value: fee
	});
	senderSpendTx.addOutput({
		script: senderP2TR,
		amount
	});
	const hashLockScript = createHashLockScript(hash, hashLockDestinationPubkey);
	const sequenceLockScript = createSequenceLockScript(lightningHTLCSequence, sequenceLockDestinationPubkey);
	const p2 = p2tr(numsKey, taprootListToTree([{
		leafVersion: 192,
		script: hashLockScript
	}, {
		leafVersion: 192,
		script: sequenceLockScript
	}]), network, true);
	const entry = p2.tapLeafScript.find(([, scriptWithVer]) => Buffer.compare(scriptWithVer.slice(0, -1), sequenceLockScript) === 0);
	const controlBlockBytes = TaprootControlBlock.encode(entry[0]);
	const seqLeafEntry = p2.tapLeafScript.find(([_, leaf]) => {
		return equalBytes(leaf.subarray(0, leaf.length - 1), sequenceLockScript);
	});
	const sighash = senderSpendTx.preimageWitnessV1(0, [sequenceLockScript], SigHash.DEFAULT, [htlcTx.getOutput(0)?.amount]);
	senderSpendTx.updateInput(0, {
		witnessUtxo: {
			script: p2.script,
			amount: htlcTx.getOutput(0)?.amount
		},
		tapLeafScript: [seqLeafEntry]
	});
	return {
		senderSpendTx,
		sighash,
		sequenceLockScript,
		controlBlockBytes
	};
}
function createReceiverSpendTx({ htlcTx, network, hash, hashLockDestinationPubkey, sequenceLockDestinationPubkey, fee }) {
	const numsKey = numsPoint();
	const spendTx = new Transaction({
		version: 3,
		allowUnknownOutputs: true,
		allowUnknownInputs: true
	});
	spendTx.addInput({
		txid: hexToBytes(getTxId(htlcTx)),
		index: 0
	});
	const senderP2TR = p2tr(sequenceLockDestinationPubkey.slice(1, 33), void 0, network, true).script;
	const amount = htlcTx.getOutput(0)?.amount - BigInt(fee);
	if (amount <= 0n) throw new SparkValidationError("Fee is greater than the amount", {
		field: "fee",
		value: fee
	});
	spendTx.addOutput({
		script: senderP2TR,
		amount
	});
	const hashLockScript = createHashLockScript(hash, hashLockDestinationPubkey);
	const sequenceLockScript = createSequenceLockScript(lightningHTLCSequence, sequenceLockDestinationPubkey);
	const p2 = p2tr(numsKey, taprootListToTree([{
		leafVersion: 192,
		script: hashLockScript
	}, {
		leafVersion: 192,
		script: sequenceLockScript
	}]), network, true);
	const hashLeafEntry = p2.tapLeafScript.find(([_, leaf]) => {
		return equalBytes(leaf.subarray(0, leaf.length - 1), hashLockScript);
	});
	spendTx.updateInput(0, {
		witnessUtxo: {
			script: p2.script,
			amount: htlcTx.getOutput(0)?.amount
		},
		tapLeafScript: [hashLeafEntry]
	});
	return {
		spendTx,
		controlBlockBytes: TaprootControlBlock.encode(hashLeafEntry[0]),
		leafHash: tapLeafHash(hashLockScript, 192),
		hashLockScript
	};
}

