//#region src/tests/utils/test-faucet.ts
const STATIC_FAUCET_KEY = hexToBytes("deadbeef1337cafe4242424242424242deadbeef1337cafe4242424242424242");
const STATIC_MINING_KEY = hexToBytes("1337cafe4242deadbeef4242424242421337cafe4242deadbeef424242424242");
const SATS_PER_BTC = 1e8;
const REFILL_AMOUNT = 10000000n;
const COIN_AMOUNT = 1000000n;
const FEE_AMOUNT = 1000n;
const TARGET_NUM_COINS = 20;
var BitcoinFaucet = class BitcoinFaucet {
	coins = [];
	static instance = null;
	miningAddress;
	lock = Promise.resolve();
	constructor(url, username, password) {
		this.url = url;
		this.username = username;
		this.password = password;
		this.miningAddress = getP2TRAddressFromPublicKey(secp256k1.getPublicKey(STATIC_MINING_KEY), Network.LOCAL);
	}
	static getInstance() {
		if (!BitcoinFaucet.instance) BitcoinFaucet.instance = new BitcoinFaucet(process.env.BITCOIN_RPC_URL || (process.env.MINIKUBE_IP ? `http://${process.env.MINIKUBE_IP}:8332` : "http://127.0.0.1:8332"), process.env.BITCOIN_RPC_USER || "testutil", process.env.BITCOIN_RPC_PASSWORD || "testutilpassword");
		return BitcoinFaucet.instance;
	}
	async withLock(operation) {
		const current = this.lock;
		let resolve;
		this.lock = new Promise((r) => resolve = r);
		await current;
		try {
			return await operation();
		} finally {
			resolve();
		}
	}
	async fund() {
		return this.withLock(async () => {
			if (this.coins.length === 0) await this.refill();
			const coin = this.coins[0];
			if (!coin) throw new Error("Failed to get coin from faucet");
			this.coins = this.coins.slice(1);
			return coin;
		});
	}
	async refill() {
		const minerPubKey = secp256k1.getPublicKey(STATIC_MINING_KEY);
		const address = getP2TRAddressFromPublicKey(minerPubKey, Network.LOCAL);
		const scanResult = await this.call("scantxoutset", ["start", [`addr(${address})`]]);
		let selectedUtxo;
		let selectedUtxoAmountSats;
		if (scanResult.success && scanResult.unspents.length > 0) {
			selectedUtxo = scanResult.unspents.find((utxo) => {
				const isValueEnough = BigInt(Math.floor(utxo.amount * SATS_PER_BTC)) >= COIN_AMOUNT + FEE_AMOUNT;
				const isMature = scanResult.height - utxo.height >= 100;
				return isValueEnough && isMature;
			});
			if (selectedUtxo) selectedUtxoAmountSats = BigInt(Math.floor(selectedUtxo.amount * SATS_PER_BTC));
		}
		if (!selectedUtxo) {
			const fundingTxid = await this.sendToAddressInternal(address, Number(REFILL_AMOUNT));
			await this.generateToAddress(1, address);
			const fundingTxRaw = await this.getRawTransaction(fundingTxid);
			const fundingTx = Transaction.fromRaw(hexToBytes(fundingTxRaw.hex));
			for (let i = 0; i < fundingTx.outputsLength; i++) {
				const output = fundingTx.getOutput(i);
				if (!output.script || !output.amount) continue;
				if (getP2TRAddressFromPkScript(output.script, Network.LOCAL) === address && output.amount === REFILL_AMOUNT) {
					selectedUtxo = {
						txid: fundingTxid,
						vout: i,
						amount: REFILL_AMOUNT
					};
					selectedUtxoAmountSats = REFILL_AMOUNT;
					break;
				}
			}
		}
		if (!selectedUtxo) throw new Error("No UTXO large enough to create even one faucet coin");
		const maxPossibleCoins = Number((selectedUtxoAmountSats - FEE_AMOUNT) / COIN_AMOUNT);
		const numCoinsToCreate = Math.min(maxPossibleCoins, TARGET_NUM_COINS);
		if (numCoinsToCreate < 1) throw new Error(`Selected UTXO (${selectedUtxoAmountSats} sats) is too small to create even one faucet coin of ${COIN_AMOUNT} sats`);
		const splitTx = new Transaction();
		splitTx.addInput({
			txid: selectedUtxo.txid,
			index: selectedUtxo.vout
		});
		const script = getP2TRScriptFromPublicKey(secp256k1.getPublicKey(STATIC_FAUCET_KEY), Network.LOCAL);
		for (let i = 0; i < numCoinsToCreate; i++) splitTx.addOutput({
			script,
			amount: COIN_AMOUNT
		});
		const remainingValue = selectedUtxoAmountSats - COIN_AMOUNT * BigInt(numCoinsToCreate) - FEE_AMOUNT;
		const minerScript = getP2TRScriptFromPublicKey(minerPubKey, Network.LOCAL);
		if (remainingValue > 0n) splitTx.addOutput({
			script: minerScript,
			amount: remainingValue
		});
		const signedSplitTx = await this.signFaucetCoin(splitTx, {
			amount: selectedUtxoAmountSats,
			script: minerScript
		}, STATIC_MINING_KEY);
		await this.broadcastTx(bytesToHex(signedSplitTx.extract()));
		const splitTxId = signedSplitTx.id;
		for (let i = 0; i < numCoinsToCreate; i++) this.coins.push({
			key: STATIC_FAUCET_KEY,
			outpoint: {
				txid: hexToBytes(splitTxId),
				index: i
			},
			txout: signedSplitTx.getOutput(i)
		});
	}
	async sendFaucetCoinToP2WPKHAddress(pubKey) {
		const sendToPubKeyTx = new Transaction();
		const p2wpkhAddress = btc.p2wpkh(pubKey, getNetwork(Network.LOCAL)).address;
		if (!p2wpkhAddress) throw new Error("Invalid P2WPKH address");
		const coinToSend = await this.fund();
		if (!coinToSend) throw new Error("No coins available");
		sendToPubKeyTx.addInput(coinToSend.outpoint);
		sendToPubKeyTx.addOutputAddress(p2wpkhAddress, COIN_AMOUNT - FEE_AMOUNT, getNetwork(Network.LOCAL));
		const signedTx = await this.signFaucetCoin(sendToPubKeyTx, coinToSend.txout, coinToSend.key);
		await this.broadcastTx(bytesToHex(signedTx.extract()));
	}
	async signFaucetCoin(unsignedTx, fundingTxOut, key) {
		const pubKey = secp256k1.getPublicKey(key);
		const internalKey = pubKey.slice(1);
		const script = getP2TRScriptFromPublicKey(pubKey, Network.LOCAL);
		unsignedTx.updateInput(0, {
			tapInternalKey: internalKey,
			witnessUtxo: {
				script,
				amount: fundingTxOut.amount
			}
		});
		const sighash = unsignedTx.preimageWitnessV1(0, new Array(unsignedTx.inputsLength).fill(script), SigHash.DEFAULT, new Array(unsignedTx.inputsLength).fill(fundingTxOut.amount));
		const tweakedKey = taprootTweakPrivKey(key, new Uint8Array());
		if (!tweakedKey) throw new Error("Invalid private key for taproot tweaking");
		const signature = schnorr.sign(sighash, tweakedKey);
		unsignedTx.updateInput(0, { tapKeySig: signature });
		unsignedTx.finalize();
		return unsignedTx;
	}
	async mineBlocks(numBlocks) {
		return await this.generateToAddress(numBlocks, this.miningAddress);
	}
	async mineBlocksAndWaitForMiningToComplete(numBlocks) {
		const startBlock = await this.getBlockCount();
		await this.mineBlocks(numBlocks);
		await this.waitForBlocksMined({
			startBlock,
			expectedIncrease: numBlocks
		});
	}
	async call(method, params) {
		try {
			const { fetch, Headers } = getFetch();
			const data = await (await fetch(this.url, {
				method: "POST",
				headers: new Headers({
					"Content-Type": "application/json",
					Authorization: "Basic " + btoa(`${this.username}:${this.password}`)
				}),
				body: JSON.stringify({
					jsonrpc: "1.0",
					id: "spark-js",
					method,
					params
				})
			})).json();
			if (data.error) {
				console.error(`RPC Error for method ${method}:`, data.error);
				throw new SparkRequestError(`Bitcoin RPC error`, {
					bitcoinRpcMethod: method,
					params,
					code: data.error.code,
					error: data.error
				});
			}
			return data.result;
		} catch (error) {
			if (error instanceof SparkRequestError) throw error;
			throw new SparkRequestError("Failed to call Bitcoin RPC", {
				bitcoinRpcMethod: method,
				params,
				error
			});
		}
	}
	async generateToAddress(numBlocks, address) {
		return await this.call("generatetoaddress", [numBlocks, address]);
	}
	async sendToAddressInternal(address, amountSats) {
		return await this.call("sendtoaddress", [address, amountSats / SATS_PER_BTC]);
	}
	async getBlock(blockHash) {
		return await this.call("getblock", [blockHash, 2]);
	}
	async getBlockCount() {
		return await this.call("getblockcount", []);
	}
	async waitForBlocksMined({ startBlock, expectedIncrease, timeoutMs = 3e4, intervalMs = 100 }) {
		const deadline = Date.now() + timeoutMs;
		await new Promise((r) => setTimeout(r, intervalMs));
		const target = startBlock + expectedIncrease;
		while (Date.now() < deadline) {
			const currentBlock = await this.getBlockCount();
			if (currentBlock >= target) return currentBlock;
			await new Promise((r) => setTimeout(r, intervalMs));
		}
		throw new Error(`Timed out waiting for ${expectedIncrease} blocks (target height ${target})`);
	}
	async broadcastTx(txHex) {
		return await this.call("sendrawtransaction", [txHex, 0]);
	}
	async submitPackage(txHexs) {
		return await this.call("submitpackage", [txHexs]);
	}
	async getNewAddress() {
		const key = secp256k1.utils.randomPrivateKey();
		return getP2TRAddressFromPublicKey(secp256k1.getPublicKey(key), Network.LOCAL);
	}
	async getNewExternalWPKHWallet() {
		const key = secp256k1.utils.randomPrivateKey();
		const pubKey = secp256k1.getPublicKey(key);
		return {
			address: getP2WPKHAddressFromPublicKey(pubKey, Network.LOCAL),
			key,
			pubKey
		};
	}
	async sendToAddress(address, amount, blocksToGenerate = 1) {
		const coin = await this.fund();
		if (!coin) throw new Error("No coins available");
		const tx = new Transaction();
		tx.addInput(coin.outpoint);
		const availableAmount = COIN_AMOUNT - FEE_AMOUNT;
		const destinationAddress = Address(getNetwork(Network.LOCAL)).decode(address);
		const destinationScript = OutScript.encode(destinationAddress);
		tx.addOutput({
			script: destinationScript,
			amount
		});
		const changeAmount = availableAmount - amount;
		if (changeAmount > 0) {
			const changeKey = secp256k1.utils.randomPrivateKey();
			const changeScript = getP2TRScriptFromPublicKey(secp256k1.getPublicKey(changeKey), Network.LOCAL);
			tx.addOutput({
				script: changeScript,
				amount: changeAmount
			});
		}
		const signedTx = await this.signFaucetCoin(tx, coin.txout, coin.key);
		const txHex = bytesToHex(signedTx.extract());
		await this.broadcastTx(txHex);
		const randomKey = secp256k1.utils.randomPrivateKey();
		const randomAddress = getP2TRAddressFromPublicKey(secp256k1.getPublicKey(randomKey), Network.LOCAL);
		await this.generateToAddress(blocksToGenerate, randomAddress);
		return signedTx;
	}
	async getRawTransaction(txid) {
		return await this.call("getrawtransaction", [txid, 2]);
	}
	async getRawMempool() {
		return await this.call("getrawmempool", []);
	}
	async getMempoolEntry(txid) {
		return await this.call("getmempoolentry", [txid]);
	}
	async waitForMempoolEntry(txid, timeoutMs = 3e4, intervalMs = 5e3) {
		const deadline = Date.now() + timeoutMs;
		while (Date.now() < deadline) try {
			const mempoolEntry = await this.getMempoolEntry(txid);
			if (mempoolEntry) return mempoolEntry;
		} catch (error) {
			await new Promise((r) => setTimeout(r, intervalMs));
		}
		throw new Error(`Timed out waiting for mempool entry for txid ${txid}`);
	}
};

