			const internalBalance = this.getInternalBalance();
			if (amountSats > internalBalance) throw new SparkValidationError("Insufficient balance", {
				field: "balance",
				value: internalBalance,
				expected: `${amountSats} sats`
			});
			const selectedLeaves = (await this.selectLeaves([amountSats])).get(amountSats);
			let leaves = this.popOrThrow(selectedLeaves, `no leaves for ${amountSats}`);
			leaves = await this.checkRenewLeaves(leaves);
			const leavesToSend = await Promise.all(leaves.map(async (leaf) => ({
				leaf,
				keyDerivation: {
					type: KeyDerivationType.LEAF,
					path: leaf.id
				},
				newKeyDerivation: { type: KeyDerivationType.RANDOM }
			})));
